 17→}
 18→
 19→/// Events from Claude Code process
 20→#[derive(Debug)]
 21→pub enum ClaudeEvent {
 22→    Output(ClaudeOutput),
 23→    Started { pid: u32 },
 24→    /// Claude's session ID from init event (for --resume)
 25→    SessionId(String),
 26→    Exited { code: Option<i32> },
 27→}
 28→
 29→/// Manages Claude Code CLI processes via PTY
 30→/// PTY spawning (like Crystal) may avoid tool_use ID collision bugs in -p --resume mode
 31→pub struct ClaudeProcess {
 32→    config: Config,
 33→}
 34→
 35→impl ClaudeProcess {
 36→    pub fn new(config: Config) -> Self {
 37→        Self { config }
 38→    }
 39→
 40→    /// Spawn Claude Code with the given prompt via PTY
 41→    /// resume_session_id: Claude session ID from previous prompt's init event (for --resume)
 42→    /// model: optional model override (e.g. "opus", "sonnet", "haiku") — passed as --model flag
 43→    pub fn spawn(
 44→        &self,
 45→        working_dir: &Path,
 46→        prompt: &str,
 47→        resume_session_id: Option<&str>,
 48→        model: Option<&str>,
 49→    ) -> Result<(mpsc::Receiver<ClaudeEvent>, u32)> {
 50→        if prompt.is_empty() {
 51→            anyhow::bail!("Prompt cannot be empty");
 52→        }
 53→
 54→        let (tx, rx) = mpsc::channel();
 55→
 56→        // Build command with PTY (like Crystal does)
 57→        let mut cmd = CommandBuilder::new(self.config.claude_executable());
 58→
 59→        // Resume previous conversation if we have a session ID
 60→        if let Some(session_id) = resume_session_id {
 61→            cmd.arg("--resume");
 62→            cmd.arg(session_id);
 63→        }
 64→
 65→        // Model override (⌃m cycle selection)
 66→        if let Some(m) = model {
 67→            cmd.arg("--model");
 68→            cmd.arg(m);
 69→        }
 70→
 71→        // Prompt and output format
 72→        cmd.arg("-p");
 73→        cmd.arg(prompt);
 74→        cmd.arg("--verbose");
 75→        cmd.arg("--output-format");
 76→        cmd.arg("stream-json");
 77→
 78→        // Permission mode
 79→        match self.config.default_permission_mode {
 80→            PermissionMode::Ignore => {
 81→                cmd.arg("--dangerously-skip-permissions");
 82→            }
 83→            PermissionMode::Approve | PermissionMode::Ask => {}
 84→        }
 85→
 86→        // Use standard process with separate stdout/stderr to capture hooks
 87→        let mut child = Command::new(self.config.claude_executable())
 88→            .args(cmd.get_argv().iter().skip(1).map(|s| s.to_str().unwrap_or("")))
 89→            .current_dir(working_dir)
 90→            .stdin(Stdio::null())
 91→            .stdout(Stdio::piped())
 92→            .stderr(Stdio::piped())
 93→            .spawn()
 94→            .context("Failed to spawn Claude")?;
 95→
 96→        let pid = child.id();
 97→        let _ = tx.send(ClaudeEvent::Started { pid });
 98→
 99→        // Read stdout
100→        let stdout = child.stdout.take().context("Failed to get stdout")?;
101→        let tx_stdout = tx.clone();
102→        thread::spawn(move || {
103→            let reader = BufReader::new(stdout);
104→            for line_result in reader.lines() {
105→                let line = match line_result {
106→                    Ok(l) => l,
107→                    Err(_) => break,
108→                };
109→
110→                if line.is_empty() {
111→                    continue;
112→                }
113→
114→                // Extract session_id from init event using string search (avoids
115→                // full JSON parse on EVERY line — init happens once per session).
116→                if line.contains("\"subtype\":\"init\"") {
117→                    if let Ok(json) = serde_json::from_str::<serde_json::Value>(&line) {
118→                        if let Some(session_id) = json.get("session_id").and_then(|v| v.as_str()) {
119→                            let _ = tx_stdout.send(ClaudeEvent::SessionId(session_id.to_string()));
120→                        }
121→                    }
122→                }
123→
124→                let output = ClaudeOutput {
125→                    output_type: OutputType::Stdout,
126→                    data: format!("{}\n", line),
127→                };
128→                if tx_stdout.send(ClaudeEvent::Output(output)).is_err() {
129→                    break;
130→                }
131→            }
132→        });
133→
134→        // Read stderr - hooks might be here
135→        let stderr = child.stderr.take().context("Failed to get stderr")?;
136→        let tx_stderr = tx.clone();
137→        thread::spawn(move || {
138→            let reader = BufReader::new(stderr);
139→            for line_result in reader.lines() {
140→                let line = match line_result {
141→                    Ok(l) => l,
142→                    Err(_) => break,
143→                };
144→
145→                if line.is_empty() {
146→                    continue;
147→                }
148→
149→                // Send stderr output (might contain hooks)
150→                let output = ClaudeOutput {
151→                    output_type: OutputType::Stderr,
152→                    data: format!("{}\n", line),
153→                };
154→                if tx_stderr.send(ClaudeEvent::Output(output)).is_err() {
155→                    break;
156→                }
157→            }
158→        });
159→
160→        // Wait for process to exit
161→        thread::spawn(move || {
162→            let status = child.wait();
163→            let code = status.ok().and_then(|s| s.code());
164→            let _ = tx.send(ClaudeEvent::Exited { code });
165→        });
166→
167→        Ok((rx, pid))
168→    }
169→}
