165→/// Migrate old-encoding project directories to the new encoding.
166→/// Old Claude CLI versions used `replace('/', '-')` which preserved chars like `+`.
167→/// Current Claude CLI uses `replace(/[^a-zA-Z0-9]/g, '-')`.
168→/// Call once at startup to rename any stale directories.
169→///
170→/// Also performs cross-platform session linking: if the native project dir doesn't
171→/// exist but a foreign-platform dir with the same worktree suffix does, creates a
172→/// symlink (macOS/Linux) or junction (Windows) so sessions sync across machines.
173→pub fn migrate_project_dirs(worktree_paths: &[std::path::PathBuf]) {
174→    let Some(home) = dirs::home_dir() else { return };
175→    let projects_dir = home.join(".claude").join("projects");
176→    if !projects_dir.exists() { return; }
177→
178→    for wt_path in worktree_paths {
179→        let new_name = encode_project_path(wt_path);
180→        let old_name = wt_path.to_string_lossy().replace('/', "-");
181→        if new_name != old_name {
182→            let old_dir = projects_dir.join(&old_name);
183→            let new_dir = projects_dir.join(&new_name);
184→
185→            // Old dir exists but new dir doesn't → rename
186→            if old_dir.exists() && !new_dir.exists() {
187→                let _ = std::fs::rename(&old_dir, &new_dir);
188→            }
189→        }
190→
191→        // Cross-platform session linking: find a foreign-platform project dir
192→        // with the same worktree suffix and link it to the native name.
193→        let native_dir = projects_dir.join(&new_name);
194→        if !native_dir.exists() {
195→            if let Some(foreign) = find_foreign_project_dir(&projects_dir, wt_path) {
196→                link_project_dir(&foreign, &native_dir);
197→            }
198→        }
199→    }
200→}
201→
202→/// Find a foreign-platform project directory that matches the same worktree.
203→/// Extracts the repo-relative suffix (e.g. "-AZUREAL-worktrees-run") from the
204→/// worktree path and searches for any existing project dir with that suffix.
205→fn find_foreign_project_dir(projects_dir: &std::path::Path, worktree_path: &std::path::Path) -> Option<PathBuf> {
206→    // Build suffix from path components after (and including) the repo name.
207→    // e.g. /Users/foo/AZUREAL/worktrees/run → "-AZUREAL-worktrees-run"
208→    //      C:\Users\bar\AZUREAL\worktrees\run → "-AZUREAL-worktrees-run"
209→    // We use the last 3 components for worktrees (repo/worktrees/name) or
210→    // last 1 for the main repo. The suffix is platform-independent since
211→    // component names don't contain path separators.
212→    let components: Vec<&str> = worktree_path.components()
213→        .filter_map(|c| c.as_os_str().to_str())
214→        .collect();
215→
216→    // Find "worktrees" in the path to determine the suffix depth
217→    let suffix_parts = if let Some(pos) = components.iter().rposition(|&c| c == "worktrees") {
218→        // Include repo name + worktrees + branch: components[pos-1..]
219→        if pos > 0 { &components[pos - 1..] } else { &components[pos..] }
220→    } else {
221→        // Main repo: just the last component
222→        if components.is_empty() { return None; }
223→        &components[components.len() - 1..]
224→    };
225→
226→    let suffix: String = suffix_parts.iter()
227→        .map(|s| format!("-{}", s))
228→        .collect();
229→
230→    if suffix.is_empty() { return None; }
231→
232→    let native_name = encode_project_path(worktree_path);
233→    let Ok(entries) = std::fs::read_dir(projects_dir) else { return None };
234→
235→    for entry in entries.flatten() {
236→        let name = entry.file_name();
237→        let name_str = name.to_string_lossy();
238→        // Must end with same suffix, be a different name, and be a real directory
239→        if name_str.ends_with(&suffix) && *name_str != native_name && entry.path().is_dir() {
240→            return Some(entry.path());
241→        }
242→    }
243→    None
244→}
