246→/// Create a symlink (Unix) or junction (Windows) from `target` to `link`.
247→/// Windows junctions don't require elevated privileges (unlike symlinks).
248→fn link_project_dir(target: &std::path::Path, link: &std::path::Path) {
249→    #[cfg(unix)]
250→    { let _ = std::os::unix::fs::symlink(target, link); }
251→    #[cfg(windows)]
252→    {
253→        // Use junction (NTFS reparse point) — no elevation required.
254→        // Falls back to symlink_dir if junction fails.
255→        let target_abs = dunce::canonicalize(target).unwrap_or_else(|_| target.to_path_buf());
256→        let status = std::process::Command::new("cmd")
257→            .args(["/C", "mklink", "/J"])
258→            .arg(link.as_os_str())
259→            .arg(target_abs.as_os_str())
260→            .stdout(std::process::Stdio::null())
261→            .stderr(std::process::Stdio::null())
262→            .status();
263→        if !status.map(|s| s.success()).unwrap_or(false) {
264→            let _ = std::os::windows::fs::symlink_dir(target, link);
265→        }
266→    }
267→}
