269→/// Format a SystemTime as a relative or absolute time string (called once at load, not per-frame)
270→fn format_time(mtime: std::time::SystemTime) -> String {
271→    let Ok(dur) = std::time::SystemTime::now().duration_since(mtime) else {
272→        return "future".to_string();
273→    };
274→    let secs = dur.as_secs();
275→    if secs < 60 { return format!("{}s ago", secs); }
276→    if secs < 3600 { return format!("{}m ago", secs / 60); }
277→    if secs < 86400 { return format!("{}h ago", secs / 3600); }
278→    if secs < 604800 { return format!("{}d ago", secs / 86400); }
279→    // Older than a week: show date
280→    let datetime = chrono::DateTime::<chrono::Local>::from(mtime);
281→    datetime.format("%b %d").to_string()
282→}
283→
284→/// List all Claude session files for a worktree, sorted by modification time (newest first)
285→/// Returns (session_id, path, pre-formatted_time_string) to avoid per-frame formatting
286→pub fn list_claude_sessions(worktree_path: &std::path::Path) -> Vec<(String, PathBuf, String)> {
287→    let Some(project_dir) = claude_project_dir(worktree_path) else { return Vec::new() };
288→
289→    let mut sessions: Vec<(String, PathBuf, std::time::SystemTime)> = Vec::new();
290→    if let Ok(entries) = std::fs::read_dir(&project_dir) {
291→        for entry in entries.flatten() {
292→            let path = entry.path();
293→            if path.extension().map(|e| e == "jsonl").unwrap_or(false) {
294→                if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
295→                    let mtime = entry.metadata().and_then(|m| m.modified()).unwrap_or(std::time::UNIX_EPOCH);
296→                    sessions.push((stem.to_string(), path, mtime));
297→                }
298→            }
299→        }
300→    }
301→    // Sort by modification time, newest first
302→    sessions.sort_by(|a, b| b.2.cmp(&a.2));
303→    // Pre-format time strings (expensive chrono call done once, not per-frame)
304→    sessions.into_iter().map(|(id, path, mtime)| (id, path, format_time(mtime))).collect()
305→}
306→
307→/// Find the most recent Claude session for a worktree
308→pub fn find_latest_claude_session(worktree_path: &std::path::Path) -> Option<String> {
309→    list_claude_sessions(worktree_path).first().map(|(id, _, _)| id.clone())
310→}
