323→    let expanded = if let Some(rest) = raw.strip_prefix("~/") {
324→        dirs::home_dir().unwrap_or_default().join(rest)
325→    } else if raw == "~" {
326→        dirs::home_dir().unwrap_or_default()
327→    } else {
