12→impl App {
13→    /// Check if a slot's output should be displayed (active slot of viewed branch)
14→    pub fn is_viewing_slot(&self, slot_id: &str) -> bool {
15→        let is_rcr_slot = self.rcr_session.as_ref().map(|r| r.slot_id == slot_id).unwrap_or(false);
16→        !self.viewing_historic_session && (is_rcr_slot || self.current_worktree().map(|s| {
17→            self.active_slot.get(&s.branch_name).map(|a| a == slot_id).unwrap_or(false)
18→        }).unwrap_or(false))
19→    }
20→
21→    /// Apply pre-parsed Claude output to app state. Called with results from
22→    /// the background ClaudeProcessor thread — all JSON parsing already done.
23→    pub fn apply_parsed_output(
24→        &mut self,
25→        events: Vec<DisplayEvent>,
26→        parsed_json: Option<serde_json::Value>,
27→        output_type: OutputType,
28→        data: &str,
29→    ) {
30→        for event in &events {
31→            match event {
32→                DisplayEvent::ToolCall { tool_use_id, tool_name, input, .. } => {
33→                    self.pending_tool_calls.insert(tool_use_id.clone());
34→                    self.tool_status_generation += 1;
35→                    if tool_name == "Task" {
36→                        if self.active_task_tool_ids.is_empty() {
37→                            self.subagent_parent_idx = self.current_todos.iter()
38→                                .position(|t| t.status == crate::app::TodoStatus::InProgress);
39→                        }
40→                        self.active_task_tool_ids.insert(tool_use_id.clone());
41→                    }
42→                    if tool_name == "TodoWrite" {
43→                        if self.active_task_tool_ids.is_empty() {
44→                            self.current_todos = parse_todos_from_input(input);
45→                            self.todo_scroll = 0;
46→                        } else {
47→                            self.subagent_todos = parse_todos_from_input(input);
48→                            self.todo_scroll = 0;
49→                        }
50→                    }
51→                    if tool_name == "AskUserQuestion" {
52→                        self.awaiting_ask_user_question = true;
53→                        self.ask_user_questions_cache = Some(input.clone());
54→                    }
55→                }
56→                DisplayEvent::ToolResult { tool_use_id, is_error, .. } => {
57→                    self.pending_tool_calls.remove(tool_use_id);
58→                    self.tool_status_generation += 1;
59→                    if self.active_task_tool_ids.remove(tool_use_id) && self.active_task_tool_ids.is_empty() {
60→                        self.subagent_todos.clear();
61→                        self.subagent_parent_idx = None;
62→                    }
63→                    if *is_error {
64→                        self.failed_tool_calls.insert(tool_use_id.clone());
65→                        self.tool_status_generation += 1;
66→                    }
67→                }
68→                _ => {}
69→            }
70→        }
71→
72→        if let Some(ref json) = parsed_json {
73→            let mut tokens_changed = false;
74→            match json.get("type").and_then(|t| t.as_str()) {
75→                Some("assistant") => if let Some(msg) = json.get("message") {
76→                    if let Some(usage) = msg.get("usage") {
77→                        let input_t = usage.get("input_tokens").and_then(|v| v.as_u64()).unwrap_or(0);
78→                        let output_t = usage.get("output_tokens").and_then(|v| v.as_u64()).unwrap_or(0);
79→                        let cache_read = usage.get("cache_read_input_tokens").and_then(|v| v.as_u64()).unwrap_or(0);
80→                        let cache_create = usage.get("cache_creation_input_tokens").and_then(|v| v.as_u64()).unwrap_or(0);

  1→//! Claude process event handling
  2→//!
  3→//! Processes output, lifecycle, and error events from Claude subprocesses.
  4→//! slot_id is the PID string — each Claude process gets a unique slot.
  5→//! Also handles auto-sending staged prompts after Claude exits.
  6→
  7→use anyhow::Result;
  8→use crate::app::App;
  9→use crate::claude::{ClaudeEvent, ClaudeProcess};
 10→
 11→/// Handle Claude process events for a specific slot (PID string).
 12→/// After an exit event, auto-sends any staged prompt.
 13→pub fn handle_claude_event(slot_id: &str, event: ClaudeEvent, app: &mut App, claude_process: &ClaudeProcess) -> Result<()> {
 14→    let is_exit = matches!(event, ClaudeEvent::Exited { .. });
 15→
 16→    match event {
 17→        ClaudeEvent::Output(output) => app.handle_claude_output(slot_id, output.output_type, output.data),
 18→        ClaudeEvent::Started { pid } => app.handle_claude_started(slot_id, pid),
 19→        ClaudeEvent::SessionId(claude_session_id) => app.set_claude_session_id(slot_id, claude_session_id),
 20→        ClaudeEvent::Exited { code } => app.handle_claude_exited(slot_id, code),
 21→    }
 22→
 23→    // Auto-send staged prompt after Claude exits
 24→    if is_exit {
 25→        if app.staged_prompt.is_some() {
 26→            app.check_session_file();
 27→            app.poll_session_file();
 28→        }
 29→        if let Some(prompt) = app.staged_prompt.take() {
 30→            if let Some(wt_path) = app.current_worktree().and_then(|s| s.worktree_path.clone()) {
 31→                let branch = app.current_worktree().map(|s| s.branch_name.clone()).unwrap_or_default();
 32→                app.add_user_message(prompt.clone());
 33→                app.process_session_chunk(&format!("You: {}\n", prompt));
 34→                app.current_todos.clear();
 35→                let resume_id = app.get_claude_session_id(&branch).cloned();
 36→                match claude_process.spawn(&wt_path, &prompt, resume_id.as_deref(), app.selected_model.as_deref()) {
 37→                    Ok((rx, pid)) => { app.register_claude(branch, pid, rx); app.set_status("Running..."); }
 38→                    Err(e) => app.set_status(format!("Failed to start: {}", e)),
 39→                }
 40→            }
 41→        }
 42→    }
 43→    Ok(())
 44→}
