        let completed = r#"{"type":"item.completed","item":{"id":"item_1","type":"command_execution","command":"ls","aggregated_output":"file1\nfile2\n","exit_code":0,"status":"completed"}}"#;
        let (_, _) = p.parse(&format!("{}\n", started));
