        let (events, _) = p.parse(&format!("{}\n", line));
        assert_eq!(events.len(), 2); // ToolCall + ToolResult
        match &events[0] {
            DisplayEvent::ToolCall { tool_name, file_path, .. } => {
                assert_eq!(tool_name, "Edit");
