        let line = r#"{"type":"item.completed","item":{"id":"item_1","type":"file_change","changes":[{"path":"a.rs","kind":"create"},{"path":"b.rs","kind":"update"}],"status":"completed"}}"#;
        let (events, _) = p.parse(&format!("{}\n", line));
