 1→//! Background thread for Claude output JSON parsing
 2→//!
 3→//! Moves serde_json::from_str() off the main event loop thread. The main
 4→//! thread sends raw output strings; the processor parses them and returns
 5→//! DisplayEvents + pre-parsed JSON values. This eliminates 10-50ms of
 6→//! JSON parsing per tick that was blocking input during streaming.
 7→
 8→use std::sync::mpsc;
 9→use std::thread;
10→
11→use crate::events::{DisplayEvent, EventParser};
12→use crate::models::OutputType;
13→
14→/// Parsed result from the processor thread
15→pub struct ProcessedOutput {
16→    #[allow(dead_code)] // kept for debug identification
17→    pub slot_id: String,
18→    pub events: Vec<DisplayEvent>,
19→    pub parsed_json: Option<serde_json::Value>,
20→    pub output_type: OutputType,
21→    pub data: String,
22→}
23→
24→/// Commands sent to the processor thread
25→enum ProcessorInput {
26→    /// Raw Claude output to parse
27→    Parse {
28→        slot_id: String,
29→        output_type: OutputType,
30→        data: String,
31→    },
32→    /// Reset parser state (session changed)
33→    Reset,
34→}
35→
36→/// Background JSON parser for Claude streaming events
37→pub struct AgentProcessor {
38→    tx: mpsc::Sender<ProcessorInput>,
39→    rx: mpsc::Receiver<ProcessedOutput>,
40→}
41→
42→impl AgentProcessor {
43→    /// Spawn the processor background thread
44→    pub fn spawn() -> Self {
45→        let (input_tx, input_rx) = mpsc::channel();
46→        let (output_tx, output_rx) = mpsc::channel();
47→
48→        thread::Builder::new()
49→            .name("claude-parser".into())
50→            .spawn(move || {
51→                let mut parser = EventParser::new();
52→                while let Ok(input) = input_rx.recv() {
53→                    match input {
54→                        ProcessorInput::Parse { slot_id, output_type, data } => {
55→                            let (events, parsed_json) = parser.parse(&data);
56→                            let _ = output_tx.send(ProcessedOutput {
57→                                slot_id, events, parsed_json, output_type, data,
58→                            });
59→                        }
60→                        ProcessorInput::Reset => {
61→                            parser = EventParser::new();
62→                        }
63→                    }
64→                }
65→            })
66→            .expect("failed to spawn claude-parser thread");
67→
68→        AgentProcessor { tx: input_tx, rx: output_rx }
69→    }
70→
71→    /// Send raw output to the processor for JSON parsing (non-blocking)
72→    pub fn submit(&self, slot_id: String, output_type: OutputType, data: String) {
73→        let _ = self.tx.send(ProcessorInput::Parse { slot_id, output_type, data });
74→    }
75→
76→    /// Reset parser state (call on session switch)
77→    pub fn reset(&self) {
78→        let _ = self.tx.send(ProcessorInput::Reset);
79→    }
80→
81→    /// Drain all pending results, discarding them (call after session switch
82→    /// to prevent stale parsed events from the old session being applied)
83→    pub fn drain(&self) {
84→        while self.rx.try_recv().is_ok() {}
85→    }
86→
87→    /// Poll for a parsed result (non-blocking)
88→    pub fn try_recv(&self) -> Option<ProcessedOutput> {
89→        self.rx.try_recv().ok()
90→    }
91→}
