182→/// Migrate old-encoding project directories to the new encoding.
183→/// Old Claude CLI versions used `replace('/', '-')` which preserved chars like `+`.
184→/// Current Claude CLI uses `replace(/[^a-zA-Z0-9]/g, '-')`.
185→/// Call once at startup to rename any stale directories.
186→///
187→/// Also performs cross-platform session linking: if the native project dir doesn't
188→/// exist but a foreign-platform dir with the same worktree suffix does, creates a
189→/// symlink (macOS/Linux) or junction (Windows) so sessions sync across machines.
190→pub fn migrate_project_dirs(worktree_paths: &[std::path::PathBuf]) {
191→    let Some(home) = dirs::home_dir() else { return };
192→    let projects_dir = home.join(".claude").join("projects");
193→    if !projects_dir.exists() { return; }
194→
195→    for wt_path in worktree_paths {
196→        let new_name = encode_project_path(wt_path);
197→        let old_name = wt_path.to_string_lossy().replace('/', "-");
198→        if new_name != old_name {
199→            let old_dir = projects_dir.join(&old_name);
200→            let new_dir = projects_dir.join(&new_name);
201→
202→            // Old dir exists but new dir doesn't → rename
203→            if old_dir.exists() && !new_dir.exists() {
204→                let _ = std::fs::rename(&old_dir, &new_dir);
205→            }
206→        }
207→
208→        // Cross-platform session linking: find a foreign-platform project dir
209→        // with the same worktree suffix and link it to the native name.
210→        let native_dir = projects_dir.join(&new_name);
211→        if !native_dir.exists() {
212→            if let Some(foreign) = find_foreign_project_dir(&projects_dir, wt_path) {
213→                link_project_dir(&foreign, &native_dir);
214→            }
215→        }
216→    }
217→}
