219→/// Find a foreign-platform project directory that matches the same worktree.
220→/// Extracts the repo-relative suffix (e.g. "-AZUREAL-worktrees-run") from the
221→/// worktree path and searches for any existing project dir with that suffix.
222→fn find_foreign_project_dir(projects_dir: &std::path::Path, worktree_path: &std::path::Path) -> Option<PathBuf> {
223→    // Build suffix from path components after (and including) the repo name.
224→    // e.g. /Users/foo/AZUREAL/worktrees/run → "-AZUREAL-worktrees-run"
225→    //      C:\Users\bar\AZUREAL\worktrees\run → "-AZUREAL-worktrees-run"
226→    // We use the last 3 components for worktrees (repo/worktrees/name) or
227→    // last 1 for the main repo. The suffix is platform-independent since
228→    // component names don't contain path separators.
229→    let components: Vec<&str> = worktree_path.components()
230→        .filter_map(|c| c.as_os_str().to_str())
231→        .collect();
232→
233→    // Find "worktrees" in the path to determine the suffix depth
234→    let suffix_parts = if let Some(pos) = components.iter().rposition(|&c| c == "worktrees") {
235→        // Include repo name + worktrees + branch: components[pos-1..]
236→        if pos > 0 { &components[pos - 1..] } else { &components[pos..] }
237→    } else {
238→        // Main repo: just the last component
239→        if components.is_empty() { return None; }
240→        &components[components.len() - 1..]
241→    };
242→
243→    let suffix: String = suffix_parts.iter()
244→        .map(|s| format!("-{}", s))
245→        .collect();
246→
247→    if suffix.is_empty() { return None; }
248→
249→    let native_name = encode_project_path(worktree_path);
250→    let Ok(entries) = std::fs::read_dir(projects_dir) else { return None };
251→
252→    for entry in entries.flatten() {
253→        let name = entry.file_name();
254→        let name_str = name.to_string_lossy();
255→        // Must end with same suffix, be a different name, and be a real directory
256→        if name_str.ends_with(&suffix) && *name_str != native_name && entry.path().is_dir() {
257→            return Some(entry.path());
258→        }
259→    }
260→    None
261→}
