263→/// Create a symlink (Unix) or junction (Windows) from `target` to `link`.
264→/// Windows junctions don't require elevated privileges (unlike symlinks).
265→fn link_project_dir(target: &std::path::Path, link: &std::path::Path) {
266→    #[cfg(unix)]
267→    { let _ = std::os::unix::fs::symlink(target, link); }
268→    #[cfg(windows)]
269→    {
270→        // Use junction (NTFS reparse point) — no elevation required.
271→        // Falls back to symlink_dir if junction fails.
272→        let target_abs = dunce::canonicalize(target).unwrap_or_else(|_| target.to_path_buf());
273→        let status = std::process::Command::new("cmd")
274→            .args(["/C", "mklink", "/J"])
275→            .arg(link.as_os_str())
276→            .arg(target_abs.as_os_str())
277→            .stdout(std::process::Stdio::null())
278→            .stderr(std::process::Stdio::null())
279→            .status();
280→        if !status.map(|s| s.success()).unwrap_or(false) {
281→            let _ = std::os::windows::fs::symlink_dir(target, link);
282→        }
283→    }
284→}
