286→/// Format a SystemTime as a relative or absolute time string (called once at load, not per-frame)
287→fn format_time(mtime: std::time::SystemTime) -> String {
288→    let Ok(dur) = std::time::SystemTime::now().duration_since(mtime) else {
289→        return "future".to_string();
290→    };
291→    let secs = dur.as_secs();
292→    if secs < 60 { return format!("{}s ago", secs); }
293→    if secs < 3600 { return format!("{}m ago", secs / 60); }
294→    if secs < 86400 { return format!("{}h ago", secs / 3600); }
295→    if secs < 604800 { return format!("{}d ago", secs / 86400); }
296→    // Older than a week: show date
297→    let datetime = chrono::DateTime::<chrono::Local>::from(mtime);
298→    datetime.format("%b %d").to_string()
299→}
