301→/// List all Claude session files for a worktree, sorted by modification time (newest first)
302→/// Returns (session_id, path, pre-formatted_time_string) to avoid per-frame formatting
303→pub fn list_claude_sessions(worktree_path: &std::path::Path) -> Vec<(String, PathBuf, String)> {
304→    let Some(project_dir) = claude_project_dir(worktree_path) else { return Vec::new() };
305→
306→    let mut sessions: Vec<(String, PathBuf, std::time::SystemTime)> = Vec::new();
307→    if let Ok(entries) = std::fs::read_dir(&project_dir) {
308→        for entry in entries.flatten() {
309→            let path = entry.path();
310→            if path.extension().map(|e| e == "jsonl").unwrap_or(false) {
311→                if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
312→                    let mtime = entry.metadata().and_then(|m| m.modified()).unwrap_or(std::time::UNIX_EPOCH);
313→                    sessions.push((stem.to_string(), path, mtime));
314→                }
315→            }
316→        }
317→    }
318→    // Sort by modification time, newest first
319→    sessions.sort_by(|a, b| b.2.cmp(&a.2));
320→    // Pre-format time strings (expensive chrono call done once, not per-frame)
321→    sessions.into_iter().map(|(id, path, mtime)| (id, path, format_time(mtime))).collect()
322→}
