    }

    #[test]
    fn test_parse_real_codex_session_with_tools() {
        let path = Path::new("/Users/macbookpro/.codex/sessions/2026/01/01/rollout-2026-01-01T07-56-02-019b79d8-1364-79d0-a63d-9dcbfcf1c21e.jsonl");
