 3→use crate::backend::Backend;
 4→use super::App;
 5→
 6→/// Claude model cycle: opus → sonnet → haiku → opus
 7→const CLAUDE_MODELS: &[&str] = &["opus", "sonnet", "haiku"];
 8→/// Codex model cycle: o3 → o4-mini → codex-mini → o3
 9→const CODEX_MODELS: &[&str] = &["o3", "o4-mini", "codex-mini"];
10→
11→/// Default model for each backend
12→pub fn default_model(backend: Backend) -> &'static str {
13→    match backend {
14→        Backend::Claude => "opus",
15→        Backend::Codex => "o3",
16→    }
17→}
