19→impl App {
20→    /// Recompute the cached token usage badge from current session_tokens + model_context_window.
21→    /// Call this whenever session_tokens or model_context_window changes — draw path just reads the cache.
22→    pub fn update_token_badge(&mut self) {
23→        let mut pct_value = 0.0_f64;
24→        self.token_badge_cache = self.session_tokens.map(|(ctx_tokens, _)| {
25→            let base_window = self.model_context_window.unwrap_or(200_000);
26→            let window = if ctx_tokens > base_window { 1_000_000 } else { base_window };
27→            // Claude reserves ~33k tokens as auto-compact buffer (compacts at ~83.5% raw).
28→            // Subtract the buffer so percentage reflects usable context, not total window.
29→            let usable = window.saturating_sub(33_000);
30→            let pct = (ctx_tokens as f64 / usable as f64 * 100.0).min(100.0);
31→            pct_value = pct;
32→            let color = if pct < 60.0 { ratatui::style::Color::Green }
33→                else if pct < 90.0 { ratatui::style::Color::Yellow }
34→                else { ratatui::style::Color::Red };
35→            (format!(" {:.0}% ", pct), color)
36→        });
37→        // Track 95% threshold for compaction inactivity watcher
38→        let was_high = self.context_pct_high;
39→        self.context_pct_high = pct_value >= 95.0;
40→        // Reset banner state when context drops below threshold (e.g. after compaction)
41→        if was_high && !self.context_pct_high {
42→            self.compaction_banner_injected = false;
43→        }
44→    }
45→
46→    /// Short display name for the active model. Always returns the selected_model
47→    /// alias since it's always set (never None).
48→    pub fn display_model_name(&self) -> &str {
49→        self.selected_model.as_deref().unwrap_or(default_model(self.backend))
50→    }
51→
52→    /// Cycle selected_model through the backend's model list.
53→    /// Claude: opus → sonnet → haiku → opus
54→    /// Codex: o3 → o4-mini → codex-mini → o3
55→    pub fn cycle_model(&mut self) {
56→        let models = match self.backend {
57→            Backend::Claude => CLAUDE_MODELS,
58→            Backend::Codex => CODEX_MODELS,
59→        };
60→        let current = self.selected_model.as_deref().unwrap_or(models[0]);
61→        let idx = models.iter().position(|&m| m == current).unwrap_or(0);
62→        let next = models[(idx + 1) % models.len()];
63→        self.selected_model = Some(next.to_string());
