 14→    14→/// Pure computation: all git + FS I/O for worktree discovery, no App state.
 15→    15→/// Safe to run on a background thread. Returns data to apply to App.
 16→    16→pub fn compute_worktree_refresh(
 17→    17→    project_path: PathBuf,
 18→    18→    main_branch: String,
 19→    19→    worktrees_dir: PathBuf,
 20→    20→    backend: Backend,
 21→    21→) -> anyhow::Result<WorktreeRefreshResult> {
 22→    22→    let worktrees = Git::list_worktrees_detailed(&project_path)?;
 23→    23→
 24→    24→    // Repair detached HEADs (rebase state recovery, orphaned HEAD re-attach)
 25→    25→    let mut needs_refetch = false;
 26→    26→    let mut rebase_branches: Vec<(PathBuf, String)> = Vec::new();
 27→    27→    for wt in &worktrees {
 28→    28→        if wt.branch.is_some() { continue; }
 29→    29→        if !wt.is_main && !wt.path.starts_with(&worktrees_dir) { continue; }
 30→    30→        if Git::is_rebase_in_progress(&wt.path) {
 31→    31→            let git_dir = std::process::Command::new("git")
 32→    32→                .args(["rev-parse", "--git-dir"])
 33→    33→                .current_dir(&wt.path)
 34→    34→                .output()
 35→    35→                .ok()
 36→    36→                .filter(|o| o.status.success())
 37→    37→                .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string());
 38→    38→            if let Some(ref gd) = git_dir {
 39→    39→                let head_name = std::path::Path::new(gd).join("rebase-merge/head-name");
 40→    40→                if let Ok(content) = std::fs::read_to_string(&head_name) {
 41→    41→                    let branch = content.trim().strip_prefix("refs/heads/").unwrap_or(content.trim());
 42→    42→                    if !branch.is_empty() {
 43→    43→                        rebase_branches.push((wt.path.clone(), branch.to_string()));
 44→    44→                        continue;
 45→    45→                    }
 46→    46→                }
 47→    47→                let head_name = std::path::Path::new(gd).join("rebase-apply/head-name");
 48→    48→                if let Ok(content) = std::fs::read_to_string(&head_name) {
 49→    49→                    let branch = content.trim().strip_prefix("refs/heads/").unwrap_or(content.trim());
 50→    50→                    if !branch.is_empty() {
 51→    51→                        rebase_branches.push((wt.path.clone(), branch.to_string()));
 52→    52→                        continue;
 53→    53→                    }
 54→    54→                }
 55→    55→            }
 56→    56→            let _ = Git::rebase_abort(&wt.path);
 57→    57→            needs_refetch = true;
 58→    58→            continue;
 59→    59→        }
 60→    60→        let head_ok = std::process::Command::new("git")
 61→    61→            .args(["symbolic-ref", "--quiet", "HEAD"])
 62→    62→            .current_dir(&wt.path)
 63→    63→            .output()
 64→    64→            .map(|o| o.status.success())
 65→    65→            .unwrap_or(true);
 66→    66→        if !head_ok {
 67→    67→            if let Ok(out) = std::process::Command::new("git")
 68→    68→                .args(["for-each-ref", "--points-at=HEAD", "--format=%(refname:short)", "refs/heads/"])
 69→    69→                .current_dir(&wt.path)
 70→    70→                .output()
 71→    71→            {
 72→    72→                let branch = String::from_utf8_lossy(&out.stdout).trim().to_string();
 73→    73→                if let Some(target) = branch.lines().next().filter(|b| !b.is_empty()) {
 74→    74→                    let _ = std::process::Command::new("git")
 75→    75→                        .args(["checkout", target])
 76→    76→                        .current_dir(&wt.path)
 77→    77→                        .output();
 78→    78→                    needs_refetch = true;
 79→    79→                }
 80→    80→            }
 81→    81→        }
 82→    82→    }
 83→    83→    let mut worktrees = if needs_refetch {
 84→    84→        Git::list_worktrees_detailed(&project_path)?
 85→    85→    } else {
 86→    86→        worktrees
 87→    87→    };
 88→    88→    for (path, branch) in &rebase_branches {
 89→    89→        for wt in &mut worktrees {
 90→    90→            if wt.path == *path && wt.branch.is_none() {
 91→    91→                wt.branch = Some(branch.clone());
 92→    92→            }
 93→    93→        }
 94→    94→    }
 95→    95→
 96→    96→    let azureal_branches = Git::list_azureal_branches(&project_path)?;
 97→    97→
 98→    98→    let wt_paths: Vec<_> = worktrees.iter().map(|w| w.path.clone()).collect();
 99→    99→    crate::config::migrate_project_dirs(&wt_paths);
100→   100→

