282→   282→    pub fn load_session_output(&mut self) {
283→   283→        // Restore terminal for new session (save was done before selection changed)
284→   284→        self.restore_session_terminal();
285→   285→
286→   286→        self.session_lines.clear();
287→   287→        self.session_buffer.clear();
288→   288→        self.session_scroll = usize::MAX; // Start at bottom (most recent messages)
289→   289→        self.display_events.clear();
290→   290→        self.session_file_path = None;
291→   291→        self.session_file_modified = None;
292→   292→        self.session_file_size = 0;
293→   293→        self.session_file_dirty = false;
294→   294→        self.session_file_parse_offset = 0;
295→   295→        self.invalidate_render_cache();
296→   296→        // Immediately clear rendered content so no stale lines from the
297→   297→        // previous session flash while the new render is in flight.
298→   298→        self.rendered_lines_cache.clear();
299→   299→        self.session_viewport_cache.clear();
300→   300→        self.animation_line_indices.clear();
301→   301→        self.message_bubble_positions.clear();
302→   302→        self.clickable_paths.clear();
303→   303→        self.clickable_tables.clear();
304→   304→        self.table_popup = None;
305→   305→        self.clicked_path_highlight = None;
306→   306→        // Discard any in-flight render result from the previous session.
307→   307→        // The render thread may still be processing old events — advancing
308→   308→        // render_seq_applied ensures poll_render_result rejects stale results.
309→   309→        self.render_seq_applied = self.render_thread.current_seq();
310→   310→        self.render_in_flight = false;
311→   311→        // Reset deferred render state so the new session gets fast initial load
312→   312→        self.rendered_events_count = 0;
313→   313→        self.rendered_content_line_count = 0;
314→   314→        self.rendered_events_start = 0;
315→   315→        self.event_parser = crate::events::EventParser::new();
316→   316→        self.agent_processor_needs_reset = true;
317→   317→        self.selected_event = None;
318→   318→        self.pending_tool_calls.clear();
319→   319→        self.failed_tool_calls.clear();
320→   320→        self.session_tokens = None;
321→   321→        self.model_context_window = None;
322→   322→        self.token_badge_cache = None;
323→   323→        self.current_todos.clear();
324→   324→        self.subagent_todos.clear();
325→   325→        self.active_task_tool_ids.clear();
326→   326→        self.subagent_parent_idx = None;
327→   327→        self.awaiting_ask_user_question = false;
328→   328→        self.ask_user_questions_cache = None;
329→   329→
330→   330→        if let Some(session) = self.current_worktree() {
331→   331→            let branch_name = session.branch_name.clone();
332→   332→            let worktree_path = session.worktree_path.clone();
333→   333→            let session_id_from_wt = session.claude_session_id.clone();
334→   334→
335→   335→            // Try to get Claude session ID: check selected file first, then cached, then auto-discover
336→   336→            let mut claude_session_id = None;
337→   337→
338→   338→            // First check if user selected a specific session file from the dropdown
339→   339→            if let Some(idx) = self.session_selected_file_idx.get(&branch_name) {
340→   340→                if let Some(files) = self.session_files.get(&branch_name) {
341→   341→                    if let Some((id, _, _)) = files.get(*idx) {
342→   342→                        claude_session_id = Some(id.clone());
343→   343→                    }
344→   344→                }
345→   345→            }
346→   346→
347→   347→            // Fall back to stored session ID or cached ID
348→   348→            if claude_session_id.is_none() {
349→   349→                claude_session_id = session_id_from_wt
350→   350→                    .or_else(|| self.agent_session_ids.get(&branch_name).cloned());
351→   351→            }
352→   352→
353→   353→            // Auto-discover Claude session ID if not set and we have a worktree
354→   354→            if claude_session_id.is_none() {
355→   355→                if let Some(ref wt_path) = worktree_path {
356→   356→                    if let Some(discovered_id) = crate::config::find_latest_session(self.backend, wt_path) {
357→   357→                        self.agent_session_ids.insert(branch_name.clone(), discovered_id.clone());
358→   358→                        claude_session_id = Some(discovered_id);
359→   359→                    }
360→   360→                }
361→   361→            }
362→   362→
363→   363→            // Clear unread for the specific session being viewed, but only when the
364→   364→            // session pane is visible (not in git mode where commits replace it).
365→   365→            // Recompute branch-level unread: remove branch only if no more unread UUIDs
366→   366→            // belong to any of its sessions.
367→   367→            if self.git_actions_panel.is_none() {
368→   368→                if let Some(ref viewed_id) = claude_session_id {
369→   369→                    self.unread_session_ids.remove(viewed_id);
370→   370→                }
371→   371→                // Check if any remaining unread UUIDs belong to this branch's sessions
372→   372→                let still_unread = self.session_files.get(&branch_name)
373→   373→                    .map(|files| files.iter().any(|(uuid, _, _)| self.unread_session_ids.contains(uuid)))
374→   374→                    .unwrap_or(false);
375→   375→                if !still_unread {
376→   376→                    self.unread_sessions.remove(&branch_name);
377→   377→                }
378→   378→            }
379→   379→
380→   380→            // Try loading from Claude's session files
381→   381→            if let (Some(claude_id), Some(ref wt_path)) = (claude_session_id, &worktree_path) {
382→   382→                if let Some(session_file) = crate::config::session_file(self.backend, wt_path, &claude_id) {
383→   383→                    // Track file for live polling
384→   384→                    self.session_file_path = Some(session_file.clone());
385→   385→                    if let Ok(meta) = std::fs::metadata(&session_file) {
386→   386→                        self.session_file_modified = meta.modified().ok();
387→   387→                        self.session_file_size = meta.len();
388→   388→                    }
389→   389→
390→   390→                    let parsed = match self.backend {
391→   391→                        crate::backend::Backend::Claude => crate::app::session_parser::parse_session_file(&session_file),
392→   392→                        crate::backend::Backend::Codex => crate::app::codex_session_parser::parse_codex_session_file(&session_file),
393→   393→                    };
394→   394→                    self.display_events = parsed.events;
395→   395→                    self.pending_tool_calls = parsed.pending_tools;
396→   396→                    self.failed_tool_calls = parsed.failed_tools;
397→   397→                    self.parse_total_lines = parsed.total_lines;
398→   398→                    self.parse_errors = parsed.parse_errors;
399→   399→                    self.assistant_total = parsed.assistant_total;
400→   400→                    self.assistant_no_message = parsed.assistant_no_message;
401→   401→                    self.assistant_no_content_arr = parsed.assistant_no_content_arr;
402→   402→                    self.assistant_text_blocks = parsed.assistant_text_blocks;
403→   403→                    self.awaiting_plan_approval = parsed.awaiting_plan_approval;
404→   404→                    self.session_tokens = parsed.session_tokens;
405→   405→                    self.model_context_window = parsed.context_window;
406→   406→                    self.update_token_badge();
407→   407→                    // Extract latest TodoWrite and AskUserQuestion state from parsed events
408→   408→                    self.extract_skill_tools_from_events();
409→   409→                    // Store byte offset for incremental parsing on subsequent polls
410→   410→                    self.session_file_parse_offset = parsed.end_offset;
411→   411→
412→   412→                    // Clear pending message once it appears in the parsed events.
413→   413→                    // Scan all events from the end — Claude may have emitted many
414→   414→                    // events (hooks, tool calls, text) after the user message, pushing
415→   415→                    // it far from the tail.
416→   416→                    if let Some(ref pending) = self.pending_user_message {
417→   417→                        for event in self.display_events.iter().rev() {
418→   418→                            if let crate::events::DisplayEvent::UserMessage { content, .. } = event {
419→   419→                                if content == pending {
420→   420→                                    self.pending_user_message = None;
421→   421→                                }
422→   422→                                break; // stop at first UserMessage either way
423→   423→                            }
424→   424→                        }
425→   425→                    }
426→   426→
427→   427→                    self.invalidate_render_cache();
428→   428→                }
429→   429→            }
430→   430→        }
431→   431→
432→   432→        // Determine if we're viewing a non-active (historic) session.
433→   433→        // When true, live events from the running process are suppressed.
434→   434→        self.viewing_historic_session = false;
435→   435→        if let Some(session) = self.current_worktree() {
436→   436→            let branch = session.branch_name.clone();
437→   437→            if let Some(active_slot) = self.active_slot.get(&branch) {
438→   438→                if let Some(active_sid) = self.agent_session_ids.get(active_slot) {
439→   439→                    if let Some(viewed_sid) = self.viewed_session_id(&branch) {
440→   440→                        self.viewing_historic_session = active_sid != &viewed_sid;
441→   441→                    }
442→   442→                }
443→   443→            }
444→   444→        }
445→   445→
446→   446→        // Cache the session title for the title bar (avoids file I/O on every draw frame)
447→   447→        self.update_title_session_name();
448→   448→
449→   449→        // Load file tree for new session
450→   450→        self.load_file_tree();
451→   451→
452→   452→        // Clear viewer if no worktree is active (all deleted) — prevents stale
453→   453→        // file content from a previously selected worktree lingering on screen.
454→   454→        if self.current_worktree().is_none() {
455→   455→            self.clear_viewer();
456→   456→        }
457→   457→
458→   458→        // Register file watches for the new session file and worktree
459→   459→        self.sync_file_watches();
460→   460→
461→   461→        // Update the OS terminal title to reflect current project and branch
462→   462→        self.update_terminal_title();
463→   463→    }
