491→   491→    /// During RCR, the title is locked to "[RCR] <name>" and won't be overwritten.
492→   492→    pub fn update_title_session_name(&mut self) {
493→   493→        // RCR mode locks the title — don't let normal session logic overwrite it
494→   494→        if self.rcr_session.is_some() { return; }
495→   495→        let Some(session) = self.current_worktree() else {
