502→   502→        let session_id = self.session_selected_file_idx.get(&branch)
503→   503→            .and_then(|idx| self.session_files.get(&branch).and_then(|f| f.get(*idx)))
504→   504→            .map(|(id, _, _)| id.clone())
505→   505→            .or_else(|| self.worktrees.get(self.selected_worktree?)
506→   506→                .and_then(|s| s.claude_session_id.clone()))
507→   507→            .or_else(|| self.agent_session_ids.get(&branch).cloned());
508→   508→        self.title_session_name = match session_id {
509→   509→            Some(id) => names.get(&id).cloned().unwrap_or_else(|| format_uuid_short(&id)),
