537→   537→        // Skip while the ACTIVE slot is streaming — its live output already
538→   538→        // feeds display_events. Other concurrent slots on the same branch don't
539→   539→        // affect the displayed session file, so we only gate on the active one.
540→   540→        if self.is_active_slot_running() { return false; }
541→   541→        self.refresh_session_events();
542→   542→        true
