545→   545→    /// Lightweight refresh of session events (no terminal/file tree reload).
546→   546→    /// Uses incremental parsing — only reads new bytes appended since last parse.
547→   547→    fn refresh_session_events(&mut self) {
548→   548→        let Some(path) = self.session_file_path.clone() else { return };
549→   549→
550→   550→        // Track if we were at bottom before refresh (usize::MAX = follow mode)
551→   551→        let was_at_bottom = self.session_scroll == usize::MAX;
552→   552→
553→   553→        // Incremental parse: only read new bytes since last offset
554→   554→        let was_full_reparse = self.session_file_parse_offset == 0;
555→   555→        let parsed = match self.backend {
556→   556→            crate::backend::Backend::Claude => crate::app::session_parser::parse_session_file_incremental(
557→   557→                &path,
558→   558→                self.session_file_parse_offset,
559→   559→                &self.display_events,
560→   560→                &self.pending_tool_calls,
561→   561→                &self.failed_tool_calls,
562→   562→            ),
563→   563→            crate::backend::Backend::Codex => crate::app::codex_session_parser::parse_codex_session_file_incremental(
564→   564→                &path,
565→   565→                self.session_file_parse_offset,
566→   566→                &self.display_events,
567→   567→                &self.pending_tool_calls,
568→   568→                &self.failed_tool_calls,
569→   569→            ),
570→   570→        };
571→   571→        // Guard: if the parse returned empty events but we already had content,
572→   572→        // the file was likely temporarily unavailable (locked, atomic rewrite,
573→   573→        // or deleted during Claude Code compaction). Preserve existing display
574→   574→        // rather than wiping the session pane. The next poll will retry.
575→   575→        if parsed.events.is_empty() && !self.display_events.is_empty() && parsed.end_offset == 0 {
576→   576→            return;
577→   577→        }
578→   578→        self.display_events = parsed.events;
579→   579→        // Full re-parse replaced ALL display_events — reset render counters so the
580→   580→        // incremental render path doesn't use stale counts that reference the old
581→   581→        // event array. Without this, submit_render_request can try to slice events
582→   582→        // at the old rendered_events_count, producing garbled or missing output.
583→   583→        if was_full_reparse {
584→   584→            self.rendered_events_count = 0;
585→   585→            self.rendered_content_line_count = 0;
586→   586→            self.rendered_events_start = 0;
587→   587→        }
588→   588→        self.pending_tool_calls = parsed.pending_tools;
589→   589→        self.failed_tool_calls = parsed.failed_tools;
590→   590→        self.parse_total_lines = parsed.total_lines;
591→   591→        self.parse_errors = parsed.parse_errors;
592→   592→        self.assistant_total = parsed.assistant_total;
593→   593→        self.assistant_no_message = parsed.assistant_no_message;
594→   594→        self.assistant_no_content_arr = parsed.assistant_no_content_arr;
595→   595→        self.assistant_text_blocks = parsed.assistant_text_blocks;
596→   596→        self.awaiting_plan_approval = parsed.awaiting_plan_approval;
597→   597→        // Extract latest TodoWrite and AskUserQuestion state from parsed events
598→   598→        self.extract_skill_tools_from_events();
599→   599→        // Update tokens, context window, and model if the new parse found assistant events
600→   600→        let mut tokens_changed = false;
601→   601→        if parsed.session_tokens.is_some() {
602→   602→            self.session_tokens = parsed.session_tokens;
603→   603→            tokens_changed = true;
604→   604→        }
605→   605→        if parsed.context_window.is_some() {
606→   606→            self.model_context_window = parsed.context_window;
607→   607→            tokens_changed = true;
608→   608→        }
609→   609→        if tokens_changed { self.update_token_badge(); }
610→   610→        self.session_file_parse_offset = parsed.end_offset;
611→   611→
612→   612→        // Clear pending message once it appears in the parsed events.
613→   613→        // Scan all events from the end — Claude may have emitted many
614→   614→        // events (hooks, tool calls, text) after the user message.
615→   615→        if let Some(ref pending) = self.pending_user_message {
616→   616→            for event in self.display_events.iter().rev() {
617→   617→                if let crate::events::DisplayEvent::UserMessage { content, .. } = event {
618→   618→                    if content == pending {
619→   619→                        self.pending_user_message = None;
620→   620→                    }
621→   621→                    break; // stop at first UserMessage either way
622→   622→                }
623→   623→            }
624→   624→        }
625→   625→
626→   626→        self.invalidate_render_cache();
627→   627→
628→   628→        // Activity detected from session file — reset compaction inactivity watcher
629→   629→        self.last_session_event_time = std::time::Instant::now();
630→   630→        self.compaction_banner_injected = false;
631→   631→
632→   632→        // If we were following bottom, stay at bottom after content update
633→   633→        if was_at_bottom {
634→   634→            self.session_scroll = usize::MAX;
635→   635→        }
636→   636→    }
