 1→//! Claude session file parsing
 2→//!
 3→//! Parses Claude's JSONL session files into DisplayEvents for the TUI.
 4→
 5→use std::collections::{HashMap, HashSet};
 6→use std::fs::File;
 7→use std::io::{BufRead, BufReader};
 8→use std::path::Path;
 9→
10→use chrono::{DateTime, Duration, Utc};
11→
12→use crate::events::DisplayEvent;
13→
14→/// Result of parsing a Claude session file
15→pub struct ParsedSession {
16→    pub events: Vec<DisplayEvent>,
17→    pub pending_tools: HashSet<String>,
18→    pub failed_tools: HashSet<String>,
19→    /// Number of lines in the JSONL file
20→    pub total_lines: usize,
21→    /// Number of lines that failed to parse
22→    pub parse_errors: usize,
23→    /// Diagnostics about assistant event parsing
24→    pub assistant_total: usize,
25→    pub assistant_no_message: usize,
26→    pub assistant_no_content_arr: usize,
27→    pub assistant_text_blocks: usize,
28→    /// True if ExitPlanMode was called and no user message followed
29→    pub awaiting_plan_approval: bool,
30→    /// Byte offset after the last successfully parsed line (for incremental parsing)
31→    pub end_offset: u64,
32→    /// Latest token usage from most recent assistant event: (context_tokens, output_tokens)
33→    /// context_tokens = input_tokens + cache_read + cache_creation (effective context size)
34→    pub session_tokens: Option<(u64, u64)>,
35→    /// Model context window size detected from assistant events' message.model field
36→    pub context_window: Option<u64>,
37→    /// Model string from the last assistant event (e.g. "claude-opus-4-6")
38→    pub model: Option<String>,
39→}
40→
41→/// Persistent parser state that survives between incremental parses.
42→/// Tracks tool_call IDs → names so tool_results from new lines can resolve them,
43→/// plus parentUuid dedup maps for user-message rewrites.
44→pub struct IncrementalParserState {
45→    pub tool_calls: HashMap<String, (String, Option<String>)>,
46→    pub user_msg_by_parent: HashMap<String, (usize, DateTime<Utc>)>,
47→    pub session_slug: Option<String>,
48→}
49→
50→impl IncrementalParserState {
51→    /// Rebuild parser context from existing display_events (cheap — just scans tool_call IDs)
52→    pub fn from_events(events: &[DisplayEvent], slug: Option<String>) -> Self {
53→        let mut tool_calls = HashMap::new();
54→        let user_msg_by_parent = HashMap::new();
55→
56→        for event in events {
57→            if let DisplayEvent::ToolCall { tool_use_id, tool_name, file_path, .. } = event {
58→                tool_calls.insert(tool_use_id.clone(), (tool_name.clone(), file_path.clone()));
59→            }
60→        }
61→
62→        Self { tool_calls, user_msg_by_parent, session_slug: slug }
63→    }
64→}
65→
66→/// Parse a Claude session JSONL file into display events (full parse from byte 0)
67→pub fn parse_session_file(session_file: &Path) -> ParsedSession {
68→    parse_session_file_from(session_file, 0, None)
69→}
