19→/// Split hint segments across top and bottom borders.
20→/// Returns (top_title, bottom_title_or_none).
21→/// `label` is the mode name (e.g. " COMMAND "), `hints` is the `|`-delimited hint string.
22→/// Packs as many segments onto the top border (after label) as fit, then the rest go bottom.
23→pub fn split_title_hints(label: &str, hints: &str, max_w: usize) -> (String, Option<String>) {
24→    let full = format!("{} ({}) ", label.trim_end(), hints);
25→    if full.chars().count() <= max_w { return (format!(" {} ", full.trim()), None); }
26→
27→    let segments: Vec<&str> = hints.split(" | ").collect();
28→    // Budget for top: " LABEL (seg | seg | ...) " — label + parens + spaces
29→    let overhead = label.chars().count() + 3; // "(" + ") " after segments
30→    let top_budget = max_w.saturating_sub(overhead);
31→
32→    let mut top_parts: Vec<&str> = Vec::new();
33→    let mut top_len = 0usize;
34→    let mut split_at = 0;
35→    for (i, seg) in segments.iter().enumerate() {
36→        let sep = if top_parts.is_empty() { 0 } else { 3 };
37→        if top_len + sep + seg.chars().count() > top_budget { break; }
38→        top_len += sep + seg.chars().count();
39→        top_parts.push(seg);
40→        split_at = i + 1;
41→    }
42→
43→    let top = if top_parts.is_empty() {
44→        format!("{}", label)
45→    } else {
46→        format!("{}({}) ", label, top_parts.join(" | "))
47→    };
48→
49→    let bottom = if split_at < segments.len() {
50→        let rest = segments[split_at..].join(" | ");
51→        // Wrap in parens to match top border format, truncate to fit
52→        let content = format!("({})", rest);
53→        let trimmed: String = content.chars().take(max_w.saturating_sub(2)).collect();
54→        Some(format!(" {} ", trimmed))
55→    } else {
56→        None
57→    };
58→
59→    (top, bottom)
60→}
