 16→/// Cached session data — mirrors ParsedSession plus source provenance fields
 17→#[derive(Serialize, Deserialize)]
 18→pub struct CachedSession {
 19→    /// Absolute path to the raw JSONL file this cache was built from
 20→    pub source_path: PathBuf,
 21→    /// Byte size of the raw JSONL at time of last parse (invalidation key)
 22→    pub source_size: u64,
 23→    /// Byte offset for incremental resumption against raw JSONL
 24→    pub parse_offset: u64,
 25→    pub events: Vec<DisplayEvent>,
 26→    pub pending_tools: HashSet<String>,
 27→    pub failed_tools: HashSet<String>,
 28→    pub session_tokens: Option<(u64, u64)>,
 29→    pub context_window: Option<u64>,
 30→    pub model: Option<String>,
