 84→/// Returns `.azureal/sessions/<session-id>.json`
 85→pub fn cache_path(project_root: &Path, session_id: &str) -> PathBuf {
 86→    project_root.join(".azureal").join("sessions").join(format!("{session_id}.json"))
 87→}
 88→
 89→/// Write parsed session to cache (atomic: write tmp then rename)
 90→pub fn write_cache(project_root: &Path, session_id: &str, cached: &CachedSession) -> io::Result<()> {
 91→    let path = cache_path(project_root, session_id);
 92→    if let Some(parent) = path.parent() {
 93→        fs::create_dir_all(parent)?;
 94→    }
 95→    let tmp = path.with_extension("json.tmp");
 96→    let data = serde_json::to_vec(cached)?;
 97→    fs::write(&tmp, &data)?;
 98→    fs::rename(&tmp, &path)?;
 99→    Ok(())
100→}
101→
102→/// Read cache if valid — source_path and source_size must both match
103→pub fn read_cache(
104→    project_root: &Path,
105→    session_id: &str,
106→    source_path: &Path,
107→    current_source_size: u64,
108→) -> Option<CachedSession> {
109→    let path = cache_path(project_root, session_id);
110→    let data = fs::read(&path).ok()?;
111→    let cached: CachedSession = serde_json::from_slice(&data).ok()?;
112→    if cached.source_path != source_path || cached.source_size != current_source_size {
113→        return None;
114→    }
115→    Some(cached)
116→}
117→
118→/// Read cache without source validation (for when raw file is missing)
119→pub fn read_cache_orphan(project_root: &Path, session_id: &str) -> Option<CachedSession> {
120→    let path = cache_path(project_root, session_id);
121→    let data = fs::read(&path).ok()?;
122→    serde_json::from_slice(&data).ok()
123→}
