  1→//! Display events for TUI rendering
  2→//!
  3→//! Processed events ready for the UI, transformed from raw Claude Code events.
  4→
  5→/// Parsed and displayable event for the UI
  6→#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
  7→pub enum DisplayEvent {
  8→    /// System initialization
  9→    Init {
 10→        _session_id: String,
 11→        cwd: String,
 12→        model: String,
 13→    },
 14→    /// Hook output
 15→    Hook {
 16→        name: String,
 17→        output: String,
 18→    },
 19→    /// User's message
 20→    UserMessage {
 21→        _uuid: String,
 22→        content: String,
 23→    },
 24→    /// Slash command (e.g., /compact, /crt)
 25→    Command {
 26→        name: String,
 27→    },
 28→    /// Context compacted (detected from compaction summary in session file)
 29→    Compacting,
 30→    /// Context compacted via /compact command (unreachable in -p mode)
 31→    Compacted,
 32→    /// Suspected compaction (95%+ context, 20s inactivity)
 33→    MayBeCompacting,
 34→    /// Plan mode content (from ~/.claude/plans/)
 35→    Plan {
 36→        name: String,
 37→        content: String,
 38→    },
 39→    /// Assistant text response
 40→    AssistantText {
 41→        _uuid: String,
 42→        _message_id: String,
 43→        text: String,
 44→    },
 45→    /// Tool being called
 46→    ToolCall {
 47→        _uuid: String,
 48→        tool_use_id: String,
 49→        tool_name: String,
 50→        /// Extracted file path if applicable
 51→        file_path: Option<String>,
 52→        /// Full input for display
 53→        input: serde_json::Value,
 54→    },
 55→    /// Tool result (output from a tool call)
 56→    ToolResult {
 57→        tool_use_id: String,
 58→        tool_name: String,
 59→        /// For file-based tools: the path that was operated on
 60→        file_path: Option<String>,
 61→        /// The raw output content from the tool
 62→        content: String,
 63→        /// Whether Claude Code flagged this result as an error
 64→        is_error: bool,
 65→    },
 66→    /// Session complete
 67→    Complete {
 68→        _session_id: String,
 69→        success: bool,
 70→        duration_ms: u64,
 71→        cost_usd: f64,
 72→    },
 73→    /// Filtered out (used for rewound/edited messages that were superseded)
 74→    Filtered,
 75→}
