 13→    13→
 14→    14→/// Map internal tool names to user-friendly display names
 15→    15→pub fn tool_display_name(tool_name: &str) -> &str {
 16→    16→    match tool_name {
 17→    17→        "Grep" | "grep" => "Search",
 18→    18→        "Glob" | "glob" => "Find",
 19→    19→        _ => tool_name,
 20→    20→    }
 21→    21→}
 22→    22→
 23→    23→/// Extract the most relevant parameter from a tool's input for display
 24→    24→pub fn extract_tool_param(tool_name: &str, input: &serde_json::Value) -> String {
 25→    25→    match tool_name {
 26→    26→        "Read" | "read" => {
 27→    27→            input.get("file_path")
 28→    28→                .or_else(|| input.get("path"))
 29→    29→                .and_then(|v| v.as_str())
 30→    30→                .unwrap_or("")
 31→    31→                .to_string()
 32→    32→        }
 33→    33→        "Write" | "write" => {
 34→    34→            input.get("file_path")
 35→    35→                .or_else(|| input.get("path"))
 36→    36→                .and_then(|v| v.as_str())
 37→    37→                .unwrap_or("")
 38→    38→                .to_string()
 39→    39→        }
 40→    40→        "Edit" | "edit" => {
 41→    41→            input.get("file_path")
 42→    42→                .or_else(|| input.get("path"))
 43→    43→                .and_then(|v| v.as_str())
 44→    44→                .unwrap_or("")
 45→    45→                .to_string()
 46→    46→        }
 47→    47→        "Bash" | "bash" => {
 48→    48→            // Full command - no truncation
 49→    49→            input.get("command").and_then(|v| v.as_str()).unwrap_or("").to_string()
 50→    50→        }
 51→    51→        "Glob" | "glob" => {
 52→    52→            input.get("pattern").and_then(|v| v.as_str()).unwrap_or("").to_string()
 53→    53→        }
 54→    54→        "Grep" | "grep" => {
 55→    55→            input.get("pattern").and_then(|v| v.as_str()).unwrap_or("").to_string()
 56→    56→        }
 57→    57→        "WebFetch" | "webfetch" => {
 58→    58→            input.get("url").and_then(|v| v.as_str()).unwrap_or("").to_string()
 59→    59→        }
 60→    60→        "WebSearch" | "websearch" => {
 61→    61→            input.get("query").and_then(|v| v.as_str()).unwrap_or("").to_string()
 62→    62→        }
 63→    63→        "Task" | "task" => {
 64→    64→            let agent_type = input.get("subagent_type").and_then(|v| v.as_str()).unwrap_or("agent");
 65→    65→            let desc = input.get("description").and_then(|v| v.as_str()).unwrap_or("");
 66→    66→            format!("[{}] {}", agent_type, desc)
 67→    67→        }
 68→    68→        "LSP" | "lsp" => {
 69→    69→            let op = input.get("operation").and_then(|v| v.as_str()).unwrap_or("");
 70→    70→            let file = input.get("filePath").and_then(|v| v.as_str()).unwrap_or("");
 71→    71→            format!("{} {}", op, file)
 72→    72→        }
 73→    73→        "EnterPlanMode" => "🔍 Planning...".to_string(),
 74→    74→        "ExitPlanMode" => "📋 Plan complete".to_string(),
 75→    75→        _ => {
 76→    76→            // Full parameter - no truncation
 77→    77→            input.get("file_path")
 78→    78→                .or_else(|| input.get("path"))
 79→    79→                .or_else(|| input.get("command"))
 80→    80→                .or_else(|| input.get("query"))
 81→    81→                .or_else(|| input.get("pattern"))
 82→    82→                .and_then(|v| v.as_str())
 83→    83→                .unwrap_or("")
 84→    84→                .to_string()
 85→    85→        }
 86→    86→    }
 87→    87→}
 88→    88→
 89→    89→/// Truncate a line to max length with ellipsis indicator
 90→    90→pub fn truncate_line(s: &str, max_len: usize) -> String {
 91→    91→    let trimmed = s.trim();
 92→    92→    if trimmed.chars().count() <= max_len {
 93→    93→        trimmed.to_string()
 94→    94→    } else if max_len > 1 {
 95→    95→        format!("{}…", trimmed.chars().take(max_len - 1).collect::<String>())
 96→    96→    } else {
 97→    97→        "…".to_string()
 98→    98→    }
 99→    99→}
100→   100→
101→   101→/// Render tool result output based on tool type
102→   102→/// Shows summarized output constrained to max_width
103→   103→pub fn render_tool_result(tool_name: &str, _file_path: Option<&str>, content: &str, is_failed: bool, max_width: usize) -> Vec<Line<'static>> {
104→   104→    let mut lines = Vec::new();
105→   105→    let tool_color = if is_failed { Color::Red } else { AZURE };
106→   106→    let result_style = Style::default().fg(if is_failed { Color::Red } else { Color::Gray });
107→   107→
108→   108→    // Filter out system-reminder blocks
109→   109→    let content = if let Some(start) = content.find("<system-reminder>") {
110→   110→        &content[..start]
111→   111→    } else {
112→   112→        content
113→   113→    }.trim_end();
114→   114→
115→   115→    let content_lines: Vec<&str> = content.lines().collect();
116→   116→    let line_count = content_lines.len();
117→   117→    // Account for " ┃  └─ " prefix (7 chars)
118→   118→    let text_max = max_width.saturating_sub(8);
119→   119→
120→   120→    if line_count == 0 {
121→   121→        let msg = match tool_name {
122→   122→            "Read" => "(empty file)",
123→   123→            "Bash" => "✓",
124→   124→            _ => "✓",
125→   125→        };
126→   126→        lines.push(Line::from(vec![
127→   127→            Span::styled(" ┃  └─ ", result_style.fg(tool_color)),
128→   128→            Span::styled(msg, if tool_name == "Bash" { Style::default().fg(Color::Green) } else { result_style }),
129→   129→        ]));
130→   130→        return lines;
131→   131→    }
132→   132→
133→   133→    // Tool-specific summarization
134→   134→    match tool_name {
135→   135→        "Read" | "read" => {
136→   136→            // First + last line with line count
137→   137→            let first = truncate_line(content_lines[0], text_max);
138→   138→            lines.push(Line::from(vec![
139→   139→                Span::styled(" ┃  │ ", result_style.fg(tool_color)),
140→   140→                Span::styled(first, result_style),
141→   141→            ]));
142→   142→            if line_count > 2 {
143→   143→                lines.push(Line::from(vec![
144→   144→                    Span::styled(" ┃  │ ", result_style.fg(tool_color)),
145→   145→                    Span::styled(format!("  ({} lines)", line_count), Style::default().fg(Color::DarkGray)),
146→   146→                ]));
147→   147→            }
148→   148→            if line_count > 1 {
