    fn compact_bash_result_keeps_last_two() {
        let content = "step 1\nstep 2\nstep 3\n\nresult line 1\nresult line 2";
        let result = compact_tool_result("Bash", content);
        assert_eq!(result, "result line 1\nresult line 2");
    }

